(() => { const screen = document.querySelector('.mobile-screen'); if (!screen) return; const live = screen.querySelector('.live-region'); const setState = state => { screen.dataset.state = state; if (live) live.textContent = state === 'success' ? '결제가 완료되었습니다.' : state === 'loading' ? '결제를 처리하고 있습니다.' : ''; }; screen.querySelectorAll('[data-action="submit-payment"]').forEach(button => button.addEventListener('click', () => { if (screen.dataset.state === 'success') return; setState('loading'); window.setTimeout(() => setState('success'), 80); })); screen.querySelectorAll('input[data-focus-scroll]').forEach(input => input.addEventListener('focus', () => window.setTimeout(() => input.scrollIntoView({ block: 'center', behavior: 'smooth' }), 0))); const profile = new URLSearchParams(location.search).get('profile') || 'standard'; screen.dataset.profile = profile; if (profile === 'short-keyboard') screen.classList.add('keyboard-open'); })();